CREATE OR REPLACE VIEW HAVEN_BASE.AZTEC_COMPLEX.PRODUCTLINE ( TRANSACTIONID, DATE, BUSINESSDATE, TERMINALID, EMPLOYEEID, ACCOUNTID, TRANSACTION_NUMBER, "ORDER", ORDERLINE, CORRECTEDORDERLINE, QUANTITY, PRICE, MOVETYPE, PRODUCT, HALF, RATIO, PORTION, CORRECTIONMETHOD, CORRECTIONREASON, TARIFFPRICE, LMDT, OWNERID, UNITPRICE, AUTHORISER, SPECIALVOUCHERSALE, ORDERDESTINATION, MULTICHOICEMODE, PRICETYPE, ORIGINALDATETIME ) AS SELECT "TRANSACTIONID", "DATE", "BUSINESSDATE", "TERMINALID", "EMPLOYEEID", "ACCOUNTID", "TRANSACTION NUMBER", "ORDER", "ORDERLINE", "CORRECTEDORDERLINE", "QUANTITY", "PRICE", "MOVETYPE", "PRODUCT", "HALF", "RATIO", "PORTION", "CORRECTIONMETHOD", "CORRECTIONREASON", "TARIFFPRICE", "LMDT", "OWNERID", "UNITPRICE", "AUTHORISER", "SPECIALVOUCHERSALE", "ORDERDESTINATION", "MULTICHOICEMODE", "PRICETYPE", "ORIGINALDATETIME" FROM "HAVEN_RAW"."AZTEC_COMPLEX"."PRODUCTLINE";

CREATE OR REPLACE VIEW HAVEN_BASE.AZTEC_COMPLEX.THEMEBUTTONMENU ( "ORDER", LEVEL, BUTTONSQL, MENUTITLE, MENUTITLESQL, MULTITITLE, MULTITITLEFILTERFIELD ) AS SELECT "ORDER", "LEVEL", "BUTTONSQL", "MENUTITLE", "MENUTITLESQL", "MULTITITLE", "MULTITITLEFILTERFIELD" FROM "HAVEN_RAW"."AZTEC_COMPLEX"."THEMEBUTTONMENU";